 1	import type { FC } from 'react';
 2	
 3	import {
 4	  EmptyState,
 5	  EmptyStateActions,
 6	  EmptyStateBody,
 7	  EmptyStateFooter,
 8	  EmptyStateHeader,
 9	  EmptyStateVariant,
10	} from '@patternfly/react-core';
11	import { useForkliftTranslation } from '@utils/i18n';
12	
13	import AddAffinityRuleButton from './AddAffinityRuleButton';
14	import AffinityDescriptionText from './AffinityDescriptionText';
15	
16	type AffinityEmptyStateProps = {
17	  onAffinityClickAdd: () => void;
18	};
19	
20	const AffinityEmptyState: FC<AffinityEmptyStateProps> = ({ onAffinityClickAdd }) => {
21	  const { t } = useForkliftTranslation();
22	
23	  return (
24	    <EmptyState variant={EmptyStateVariant.full}>
25	      <EmptyStateHeader headingLevel="h5" titleText={<>{t('No affinity rules found')}</>} />
26	      <EmptyStateBody>
27	        <AffinityDescriptionText />
28	      </EmptyStateBody>
29	      <EmptyStateFooter>
30	        <EmptyStateActions>
31	          <AddAffinityRuleButton onAffinityClickAdd={onAffinityClickAdd} />
32	        </EmptyStateActions>
33	      </EmptyStateFooter>
34	    </EmptyState>
35	  );
36	};
37	
38	export default AffinityEmptyState;

